-- Adjust Serial Primary Key Sequences
SELECT setval('departments_department_id_seq', COALESCE((SELECT MAX(department_id)+1 FROM departments), 1), false);
SELECT setval('employees_employee_id_seq', COALESCE((SELECT MAX(employee_id)+1 FROM employees), 1), false);
SELECT setval('users_user_id_seq', COALESCE((SELECT MAX(user_id)+1 FROM users), 1), false);
SELECT setval('customers_customer_id_seq', COALESCE((SELECT MAX(customer_id)+1 FROM customers), 1), false);
SELECT setval('products_product_id_seq', COALESCE((SELECT MAX(product_id)+1 FROM products), 1), false);
SELECT setval('inventory_inventory_id_seq', COALESCE((SELECT MAX(inventory_id)+1 FROM inventory), 1), false);
SELECT setval('orders_order_id_seq', COALESCE((SELECT MAX(order_id)+1 FROM orders), 1), false);
SELECT setval('support_tickets_ticket_id_seq', COALESCE((SELECT MAX(ticket_id)+1 FROM support_tickets), 1), false);